const body = $input.item.json.body || $input.item.json || {};
const file = $input.item.binary?.file || $input.item.binary?.data;
const source = body.source || 'import';
const importId = body.import_batch_id || body.import_id || body.quote_id || `IMP_${Date.now()}`;
const jobId = body.job_id || `job_${Date.now()}`;

const successUrl = body.callbackSuccessUrl || body.callbacks?.success_url;
const failedUrl = body.callbackFailedUrl || body.callbacks?.failed_url;

if (!successUrl) {
  throw new Error("Missing callbackSuccessUrl in webhook payload!");
}

const filename = file?.fileName || file?.name || body.filename || 'document.pdf';
const rawMime = (file?.mimeType || file?.mimetype || '').toLowerCase();
const extIsPdf = filename.toLowerCase().endsWith('.pdf');

// Accept application/pdf, application/octet-stream with .pdf ext, or any missing mime with .pdf ext
const isPdf = rawMime === 'application/pdf' || extIsPdf || rawMime.includes('pdf');
const mimeType = isPdf ? 'application/pdf' : (rawMime || 'unknown');

return {
  json: {
    importId,
    jobId,
    filename,
    mime_type: mimeType,
    is_pdf: isPdf,
    callbackSuccessUrl: successUrl,
    callbackFailedUrl: failedUrl,
    source,
    source_format: 'pdf'
  },
  binary: $input.item.binary
};

const meta = $("Metadata & Validation2").first().json;
let extractedRows = [];
let errorMessage = null;

try {
  let rawText = $("OpenAI Assistants API").first().json.choices[0].message.content;
  if (rawText.includes("```json")) {
     rawText = rawText.replace(/```json/g, "").replace(/```/g, "").trim();
  }
  console.log('raw:', rawText);
  const parsed = JSON.parse(rawText);
  extractedRows = Array.isArray(parsed) ? parsed : (parsed.rows || []);
} catch(e) {
  errorMessage = "Ошибка обработки ИИ: " + e.message + ". Возможно, текст слишком большой или файл поврежден.";
}

if (!errorMessage && (!extractedRows || extractedRows.length === 0)) {
  errorMessage = "Не удалось распознать товарные позиции. Убедитесь, что файл содержит список товаров, или что текст (кодировка) читаем, а не зашифрован как картинка.";
}

if (errorMessage) {
  return {
    json: {
      import_batch_id: meta.importId,
      job_id: meta.jobId,
      status: "failed",
      error: errorMessage,
      callbackFailedUrl: meta.callbackFailedUrl
    }
  };
}

return {
  json: {
    import_batch_id: meta.importId,
    job_id: meta.jobId,
    status: "parsed",
    rows: extractedRows,
    callbackSuccessUrl: meta.callbackSuccessUrl
  }
};

return {
  json: {
    import_batch_id: $input.item.json.importId,
    job_id: $input.item.json.jobId,
    status: "failed",
    error: "Неподдерживаемый формат: " + $input.item.json.mime_type + ". Загрузите PDF-файл.",
    callbackFailedUrl: $input.item.json.callbackFailedUrl
  }
};

const meta = $("Metadata & Validation2").first().json;
const openaiKey = $("Inject API Key").first().json.openaiKey;
if (!openaiKey) throw new Error("Missing OPENAI_API_KEY");

// --- Binary access without this.helpers (Task Runner safe) ---
const binaryItem = $input.first().binary?.file;
if (!binaryItem) throw new Error("No binary file in input");
const fileName = binaryItem.fileName || 'document.pdf';
const fileBuffer = Buffer.from(binaryItem.data, 'base64');

// --- Upload file to OpenAI via fetch + manual multipart ---
const boundary = '----BahusFormBoundary' + Date.now();
const header = Buffer.from(
  `--${boundary}\r\nContent-Disposition: form-data; name="purpose"\r\n\r\nassistants\r\n` +
  `--${boundary}\r\nContent-Disposition: form-data; name="file"; filename="${fileName}"\r\nContent-Type: application/pdf\r\n\r\n`,
  'utf8'
);
const footer = Buffer.from(`\r\n--${boundary}--\r\n`, 'utf8');
const body = Buffer.concat([header, fileBuffer, footer]);

const uploadResp = await fetch('https://api.openai.com/v1/files', {
  method: 'POST',
  headers: {
    'Authorization': `Bearer ${openaiKey}`,
    'Content-Type': `multipart/form-data; boundary=${boundary}`
  },
  body: body
});
if (!uploadResp.ok) throw new Error("File upload failed: " + await uploadResp.text());
const uploadRes = await uploadResp.json();
const fileId = uploadRes.id;

let assistantId = null;

try {
  const prompt = `You are a master data extractor. Extract ALL product rows from this price list into strict JSON.
Format: {"rows": [{"name":"...","article":"...","qty":1,"purchase_price":100,"volume_l":0.75,"country":"...","category":"...","note":"..."}]}
Rules: respond ONLY with valid JSON, no markdown, no explanation. If you are unsure of a field, use null.`;

  // Create assistant
  const aResp = await fetch('https://api.openai.com/v1/assistants', {
    method: 'POST',
    headers: {
      'Authorization': `Bearer ${openaiKey}`,
      'OpenAI-Beta': 'assistants=v2',
      'Content-Type': 'application/json'
    },
    body: JSON.stringify({
      name: 'BahusExtractorTemp',
      model: 'gpt-4o',
      instructions: prompt,
      tools: [{ type: "file_search" }],
      tool_resources: { file_search: { vector_stores: [{ file_ids: [fileId] }] } }
    })
  });
  if (!aResp.ok) throw new Error("Assistant create failed: " + await aResp.text());
  const assistantRes = await aResp.json();
  assistantId = assistantRes.id;

  // Create thread + run in one call
  const runResp = await fetch('https://api.openai.com/v1/threads/runs', {
    method: 'POST',
    headers: {
      'Authorization': `Bearer ${openaiKey}`,
      'OpenAI-Beta': 'assistants=v2',
      'Content-Type': 'application/json'
    },
    body: JSON.stringify({
      assistant_id: assistantId,
      thread: {
        messages: [{ role: "user", content: "Extract all product rows from the attached price list. Return ONLY JSON." }]
      },
      response_format: { type: "json_object" }
    })
  });
  if (!runResp.ok) throw new Error("Run create failed: " + await runResp.text());
  const runRes = await runResp.json();
  const threadId = runRes.thread_id;
  const runId = runRes.id;

  // Poll until done (max 90 attempts × 3s = 4.5 min)
  let status = runRes.status;
  let attempts = 0;
  while ((status === "queued" || status === "in_progress") && attempts < 90) {
    await new Promise(r => setTimeout(r, 3000));
    attempts++;
    const pollResp = await fetch(`https://api.openai.com/v1/threads/${threadId}/runs/${runId}`, {
      headers: {
        'Authorization': `Bearer ${openaiKey}`,
        'OpenAI-Beta': 'assistants=v2'
      }
    });
    const pollRes = await pollResp.json();
    status = pollRes.status;
    if (status === "failed" || status === "cancelled" || status === "expired") {
      throw new Error(`Run ended with status: ${status}. ${JSON.stringify(pollRes.last_error || {})}`);
    }
  }
  if (status !== "completed") throw new Error(`Run timed out, last status: ${status}`);

  // Get messages
  const msgsResp = await fetch(`https://api.openai.com/v1/threads/${threadId}/messages`, {
    headers: {
      'Authorization': `Bearer ${openaiKey}`,
      'OpenAI-Beta': 'assistants=v2'
    }
  });
  const msgsRes = await msgsResp.json();

  // Cleanup
  fetch(`https://api.openai.com/v1/assistants/${assistantId}`, { method: 'DELETE', headers: {'Authorization': `Bearer ${openaiKey}`, 'OpenAI-Beta': 'assistants=v2'} }).catch(() => {});
  fetch(`https://api.openai.com/v1/files/${fileId}`, { method: 'DELETE', headers: {'Authorization': `Bearer ${openaiKey}`} }).catch(() => {});

  const contentBlock = msgsRes.data?.[0]?.content?.find(c => c.type === 'text');
  const rawText = contentBlock ? contentBlock.text.value : '{"rows":[]}';

  return { json: { choices: [{ message: { content: rawText } }] } };

} catch(e) {
  // Cleanup on error
  if (assistantId) fetch(`https://api.openai.com/v1/assistants/${assistantId}`, { method: 'DELETE', headers: {'Authorization': `Bearer ${openaiKey}`, 'OpenAI-Beta': 'assistants=v2'} }).catch(() => {});
  fetch(`https://api.openai.com/v1/files/${fileId}`, { method: 'DELETE', headers: {'Authorization': `Bearer ${openaiKey}`} }).catch(() => {});
  throw e;
}
